4	describe("Game of Life - nextGeneration", () => {
5	  it("returns an empty array when given an empty array", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("kills a single live cell with no neighbors (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("kills two adjacent live cells (each has only 1 neighbor)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("keeps a live cell alive when it has 2 live neighbors (survival)", () => {
15	    // Three in a row: center (0,0) has 2 neighbors (-1,0) and (1,0) and survives
16	    const result = nextGeneration([[-1, 0], [0, 0], [1, 0]]);
17	    const keys = new Set(result.map((c) => c.join(",")));
18	    expect(keys.has("0,0")).toBe(true);
19	  });
20	  it("keeps a live cell alive when it has 3 live neighbors (survival)", () => {
21	    // (0,0) has 3 neighbors: (1,0), (0,1), (1,1)
22	    const result = nextGeneration([[0, 0], [1, 0], [0, 1], [1, 1]]);
