32	  it("brings a dead cell to life when it has exactly 3 live neighbors (reproduction)", () => {
33	    // L-shape: (0,0), (1,0), (0,1) → dead cell (1,1) has 3 neighbors
34	    const result = nextGeneration([[0, 0], [1, 0], [0, 1]]);
