export function nextGeneration(cells: Cell[]): Cell[] {
  const aliveKeys = new Set(cells.map(cellKey));
  const neighborTally = new Map<string, { cell: Cell; count: number }>();

  for (const neighbor of cells.flatMap(neighborsOf)) {
    const key = cellKey(neighbor);
    const entry = neighborTally.get(key);
    if (entry) entry.count += 1;
    else neighborTally.set(key, { cell: neighbor, count: 1 });
  }

  return [...neighborTally.values()]
    .filter(({ cell, count }) => survives(aliveKeys.has(cellKey(cell)), count))
    .map(({ cell }) => cell);
}

